package com.welltrack.identity.config; import org.springframework.context.annotation.*; import org.springframework.security.crypto.bcrypt.*; import org.springframework.security.crypto.password.*; import org.springframework.security.web.*; import org.springframework.security.config.annotation.method.configuration.*; import org.springframework.security.config.annotation.web.builders.*; import com.welltrack.identity.security.*; @Configuration @EnableMethodSecurity public class SecurityConfig{ @Bean PasswordEncoder enc(){return new BCryptPasswordEncoder();} @Bean SecurityFilterChain chain(HttpSecurity h,JwtFilter f)throws Exception{h.csrf(cs->cs.disable()).authorizeHttpRequests(a->a.anyRequest().permitAll()).addFilterBefore(f,UsernamePasswordAuthenticationFilter.class);return h.build();}}